#include<bits/stdc++.h>
using namespace std;
__int128 dp[1000010],max1[1000010];
int a[1000010];

int main()
{
    int n,p;
    scanf("%d%d",&n,&p);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        dp[i]=max((__int128)0,dp[i-1])+a[i];
        max1[i]=max(max1[i-1],dp[i]);
    }
    __int128 mx1=a[1],mx2=a[1]+max1[1];
    for(int i=2;i<=n;i++)
    {
        __int128 t=mx2;
        mx1=max(mx1,t);
        mx2=max(mx2,t+max1[i]);
    }
    printf("%d",(int)(mx1%p));
    return 0;
}
